let selectedSign=null;function goStep(t){document.querySelectorAll(".step-view").forEach(e=>e.classList.remove("active")),document.getElementById("step-"+t).classList.add("active");for(let e=1;e<=3;e++){const o=document.getElementById("prog-"+e);o.classList.toggle("active",e===t),o.classList.toggle("done",e<t)}}function selectSign(t){document.querySelectorAll(".zodiac-btn").forEach(o=>o.classList.remove("selected")),t.classList.add("selected"),selectedSign=t.dataset.sign;const e=document.getElementById("btn-step2");e.disabled=!1,e.style.opacity="1",e.style.cursor="pointer"}function toggleInterest(t){t.classList.toggle("selected")}async function finishOnboarding(){const t=[...document.querySelectorAll(".interest-chip.selected")].map(e=>e.textContent.trim());selectedSign&&localStorage.setItem("mh_zodiac",selectedSign),t.length&&localStorage.setItem("mh_interests",JSON.stringify(t)),localStorage.setItem("mh_onboarded","1");try{const e=window.API_CONFIG?.BASE_URL||"http://localhost:3001/api",o=await fetch(`${e}/auth/onboarding/complete`,{method:"POST",credentials:"include",headers:{"Content-Type":"application/json"}});o.ok||console.warn("Failed to notify backend of onboarding completion:",o.status)}catch(e){console.warn("Error notifying backend of onboarding:",e)}window.location.href="index.html"}document.addEventListener("click",function(t){const e=t.target.closest("[data-action]");if(!e)return;const o=e.dataset.action;if(o==="goStep"){const n=parseInt(e.dataset.step);goStep(n)}else o==="selectSign"?selectSign(e):o==="toggleInterest"?toggleInterest(e):o==="finishOnboarding"&&finishOnboarding()});
